function handleIntersection(e,t){let a=new IntersectionObserver((a,l)=>{a.forEach(a=>{a.isIntersecting&&t(l,e)})},{root:null,rootMargin:"0px",threshold:.3});a.observe(e)}let ham=document.querySelector(".hamburger"),nav=document.querySelector(".navbar");ham.addEventListener("click",e=>{document.querySelectorAll(".ham-line").forEach(e=>{e.classList.toggle("active-ham-line")}),ham.classList.toggle("active-ham"),nav.classList.toggle("active-nav")});
